var e=JSON.parse(`[{"id":"L14_1","type":"dialog","speaker":"SQUADMEMBER_NPC_NULL_NULL","text":{"KOREA":"훈련 종료!","JPN":"訓練終了！","ENG":"Training completed!","TWN":"訓練結束！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SQUADMEMBER_NPC_NULL_NULL","text":{"KOREA":"어, 엄청납니다. 소령님께선 모의훈련 최단시간을 고작 일주일 사이에 거의 절반이나 단축하시다니.","JPN":"す、すごい。少佐は、模擬訓練の最短時間をたった一週間の間にほぼ半分にも短縮されましたか。","ENG":"T-that's incredible. Major Wong managed to break the record for the simulation training by half in just a week.","TWN":"太，太誇張了。少校居然把模擬訓練的最快記錄縮短了將近半個禮拜。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CAPTAIN_TOY_NULL_NULL","text":{"KOREA":"애초에 이건 분대단위로 진행하는 훈련이야. 소령님은 그걸 혼자서 해내고 계신 거라고.","JPN":"そもそもこれは分隊単位で行う訓練だ。少佐はそれを一人でこなしているんだよ。","ENG":"This training is designed for squad level units in the first place. Major Wong did that all by himself.","TWN":"這訓練一開始是以班為作戰單位進行的啊，結果少校獨自一人就完成了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SQUADMEMBER_NPC_NULL_NULL","text":{"KOREA":"현장 전투원이 아니신데도 저런 성과를 낼 수 있다니. 역시 카운터는 달라도 뭔가 다르군요.","JPN":"現場の戦闘員でもないのに、あんな成果を出すなんて。やっぱりカウンターはなんか違いますね。","ENG":"And he's not even a combat operative. I guess Counters are cut from a different cloth after all.","TWN":"明明不是現場參戰人員卻能有那種成績，果然制裁者就是不一樣啊。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CAPTAIN_TOY_NULL_NULL","text":{"KOREA":"아니. 자기가 카운터라고 떠벌려대는 용병들을 여럿 만나봤지만, 전부 거들먹거리기나 좋아하고 몸이 좀 튼튼한 정도일 뿐이었어.","JPN":"いや、カウンターだと自称する傭兵たちにたくさん会ってきたが、\\nどいつもこいつも調子に乗るだけで、体が丈夫なこと以外は何の取り柄もなかったんだ。","ENG":"No, it's not just that. I've met plenty of mercs who brag about their Counter abilities, but it was all talk. Sure, they're a bit sturdier than normal folks, but that was it.","TWN":"不，我見過很多洋洋得意，自稱是制裁者的傭兵，但他們大多就只是壯了一些罷了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAPTAIN_TOY_NULL_NULL","text":{"KOREA":"하지만 소령님은 근본부터가 달라. 카운터들 중에서도 뛰어난 엘리트니까.","JPN":"しかし、少佐は彼らと根本的に違う。カウンターたちの中でも優れたエリートなんだ。","ENG":"There's something fundamentally different about Major Wong. After all, he stands out even among the Counters.","TWN":"但少校完全不一樣，畢竟少校在制裁者裡也是精英中的精英。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"다들 오늘도 고생 많았습니다. 그만 정리하고 막사로 철수하도록 하죠.","JPN":"みんな、今日もお疲れ様でした。そろそろ片付けて兵舎に戻りましょう。","ENG":"Good work today, everyone. Let's wrap up and head back to the barracks.","TWN":"大家辛苦了。今天就到此為止，大家都回營地吧。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CAPTAIN_TOY_NULL_NULL","text":{"KOREA":"옙! 소령님!","JPN":"はっ！　少佐！","ENG":"Roger that! Sir!","TWN":"是！少校!"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"자, 자 카일 웡 소령님. 이쪽을 봐 주세요.","JPN":"さあ、さあ、カイル・ウォン少佐。こっちを見てください。","ENG":"Alright, Major Kyle Wong. Please take a look at me.","TWN":"來吧，凱爾少校。請看這邊。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"자...... 짜잔! 여기선 아무 일도 없었습니다. 그렇지 않나요?","JPN":"……ジャジャーン！　こちらでは何事もなかったです。そうでしょう？","ENG":"Now... Tah-dah! Nothing happened here, did it?","TWN":"來……鏘鏘！這裡什麼事都沒有發生。不是嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이상해.","JPN":"おかしい。","ENG":"Something is off.","TWN":"奇怪。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"아무리 뒤져봐도 분명 그날은 기지에 불법침입의 흔적이 없었는데.","JPN":"いくら調べてみてもその日は基地に不法侵入した痕跡がなかったはずだ。","ENG":"There were no signs of forcible entry into the base that day no matter how hard I looked.","TWN":"明明那天基地被非法入侵了，可是不管怎麼找都找不到痕跡。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이 어렴풋한 기억은 대체 뭐지? 내가 꿈이라도 꾼 건가?","JPN":"このぼんやりとした記憶はいったいなんだ？　僕は夢でも見たのか？","ENG":"So what's this faint memory I have? Did I dream it or something?","TWN":"這段模糊的記憶到底是什麼？難道我是在做夢嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};